"""Sprint69-1Bの4ファイルを完成版へ確実に全文置換する。"""

from __future__ import annotations

import base64
from pathlib import Path

FILES = {
    Path('app/runtime/paper_trading_day_models.py'): '',
    Path('app/runtime/paper_trading_day_service.py'): '',
    Path('app/runtime/paper_trading_day_report.py'): '',
    Path('app/runtime/daily_operation_report_post_run_hook.py'): '',
}

for path, encoded in FILES.items():
    content = base64.b64decode(encoded).decode('utf-8')
    if path.suffix == '.py':
        compile(content, str(path), 'exec')
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding='utf-8', newline='\n')
    print(f'updated: {path}')

# 実ファイルの内容を直接確認する。
models_text = Path('app/runtime/paper_trading_day_models.py').read_text(encoding='utf-8')
service_text = Path('app/runtime/paper_trading_day_service.py').read_text(encoding='utf-8')
report_text = Path('app/runtime/paper_trading_day_report.py').read_text(encoding='utf-8')
hook_text = Path('app/runtime/daily_operation_report_post_run_hook.py').read_text(encoding='utf-8')

checks = {
    'settings.continue_on_post_run_hook_error': 'continue_on_post_run_hook_error' in models_text,
    'result.completed_post_run_hook_count': 'completed_post_run_hook_count' in models_text,
    'service.post_run_hooks': 'post_run_hooks' in service_text,
    'report.post_run_hooks': '"post_run_hooks"' in report_text,
    'daily_report_hook': 'DailyOperationReportPostRunHook' in hook_text,
}

failed = [name for name, ok in checks.items() if not ok]
if failed:
    raise RuntimeError(f'置換確認に失敗しました: {failed}')

print('Sprint69-1B files were replaced successfully.')
for name in checks:
    print(f'  OK: {name}')
